import React, {useState} from 'react';
import './Navbar.css';
import {Link} from 'react-router-dom';
import Navbar from 'react-bootstrap/Navbar';
import AnchorLink from 'react-anchor-link-smooth-scroll'
import NavDropdown from 'react-bootstrap/NavDropdown';



function Nav() {
  const [click, setClick] = useState(false);


  const handleClick = () => setClick(!click);
  const closeMobileMenu = () => setClick(false);

  // const showButton = () => {
  //   if(window.innerWidth <= 960) {
  //     setButton(false)
  //   } else {
  //     setButton(true);
  //   }
  // };

  // useEffect(() => {
  //   showButton();
  // }, []);


  // window.addEventListener('resize', showButton);

return (
  <>
    <div >
      <Navbar collapseOnSelect expand="lg">
      <div className="navbar-container" >
          {/* <div className="menu-icon" onClick={handleClick}>
          </div> */}
            <ul className={click? 'nav-menu active' : 'nav-menu'}>
              <Link to="/" className='nav-links' onClick={closeMobileMenu}>
                <h1>Résonance</h1>
              </Link>


          <div className='list' >
                <li className='nav-item'>

                <AnchorLink href='/home/#cards' to="/cards" onClick={closeMobileMenu}>
                    Programme
                </AnchorLink>

                </li>
                <li className='nav-item'>
                  <Link to="/events" onClick={closeMobileMenu}>
                <NavDropdown title="Événements" id="collasible-nav-dropdown">
                  <NavDropdown.Item href="#action/3.1">Yoga</NavDropdown.Item>
                  <NavDropdown.Item href="#action/3.2">Voyage</NavDropdown.Item>
                  <NavDropdown.Item href="#action/3.3">Coaching</NavDropdown.Item>
                </NavDropdown>
                  </Link>
                </li>
                <li className='nav-item'>
                 <AnchorLink  href='#/profile' onClick={closeMobileMenu}>
                  Qui suis-je ?
                  </AnchorLink>
                </li>
                <li className='nav-item'>
                  <Link to="/events"  onClick={closeMobileMenu}>
                    Contenu
                  </Link>
                </li>
                <li className='nav-item'>
                  <AnchorLink href='#footer'  onClick={closeMobileMenu}>
                    Contact
                  </AnchorLink>
                </li>
              </div>
            </ul>
        </div>
      </Navbar>
    </div>
  </>
)
};

export default Nav;
